mapper.select:
/** com.rotemDemo.zzz.api.unit.mapper.EmplMappe.selectEmplList **/ select a.emp_id as empId ,a.emp_nm as empNm ,a.emp_alias as empAlias ,a.dept_cd as deptCd ,b.dept_nm as deptNm ,a.join_date as joinDate ,a.work_yn as workYn ,a.use_yn as useYn ,c.com_cd_nm as jobNm from zzz_emp_info a left join zzz_dept_info b on a.dept_cd = b.dept_cd left join zzz_code_info c on a.position_cd = c.com_cd AND c.supi_com_cd = 'ZZZ0004' where a.use_yn = 'Y'
and a.emp_id = #{empId}
and a.emp_nm like concat('%', #{empNm}, '%')

SELECT zei.dept_cd, zei.emp_id, zei.emp_nm, zei.work_yn, IFNULL(zei.retire_date, '') retire_date, IFNULL(zdhi.dept_cd, '') zdhi_dept_cd, IFNULL(zdhi.sd_dt, '') start_transfer_date, IFNULL(zdhi.ed_dt, '') end_transfer_date, CASE WHEN IFNULL(zdhi.ed_dt, '') = '' THEN 'Y' ELSE 'N' END AS currentDeptYn FROM rotemDemo_zzz.zzz_emp_info zei LEFT JOIN rotemDemo_zzz.zzz_emp_dept_hist zdhi ON zei.emp_id = zdhi.emp_id
AND zdhi.dept_cd IN #{deptCdItem}
AND (zdhi.ed_dt BETWEEN #{startDate} AND #{endDate} OR IFNULL(zdhi.ed_dt, '') = '') WHERE 1 = 1
AND zei.emp_id IN #{empIdItem}
AND zei.work_yn = #{workYn}
ORDER BY zdhi_dept_cd, currentDeptYn desc, zei.emp_id

WITH RECURSIVE dept_tree AS ( SELECT d.dept_cd , d.dept_parent_cd , d.sort_sn , d.dept_nm , CAST(LPAD(d.sort_sn, 5, '0') AS CHAR(200)) AS dept_path FROM rotemDemo_zzz.zzz_dept_info d WHERE d.dept_parent_cd IS NULL AND d.use_yn = 'Y' UNION ALL SELECT d.dept_cd , d.dept_parent_cd , d.sort_sn , d.dept_nm , CONCAT(t.dept_path, '-', LPAD(d.sort_sn, 5, '0')) AS dept_path FROM rotemDemo_zzz.zzz_dept_info d JOIN dept_tree t ON d.dept_parent_cd = t.dept_cd WHERE d.use_yn = 'Y' ), emp_list AS ( SELECT ei.emp_id AS empId , ei.emp_nm AS empNm , eh.dept_cd AS deptCd , GREATEST(IFNULL(NULLIF(eh.sd_dt,''),#{startDate}),#{startDate}) AS sdYear , IF(IFNULL(eh.ed_dt,'')='', IF(IFNULL(ei.retire_date,'')='',#{endDate},ei.retire_date), eh.ed_dt) AS edYear , IF(IFNULL(eh.ed_dt,'')='', IF(IFNULL(ei.retire_date,'')='','',ei.retire_date), eh.ed_dt) AS tempEdYear FROM rotemDemo_zzz.zzz_emp_dept_hist eh JOIN rotemDemo_zzz.zzz_emp_info ei ON eh.emp_id = ei.emp_id WHERE ei.use_yn = 'Y' AND (IFNULL(eh.ed_dt,'')='' OR eh.ed_dt BETWEEN #{startDate} AND #{endDate})
AND eh.dept_cd IN
#{deptCdItem}
AND ei.emp_id = #{empId}
AND ei.emp_id IN
#{empIdItem}
) SELECT e.empId , e.empNm , e.deptCd , dt.dept_nm AS deptNm , dt.dept_path AS deptPath , e.sdYear , e.edYear , e.tempEdYear FROM emp_list e LEFT JOIN dept_tree dt ON e.deptCd = dt.dept_cd ORDER BY dt.dept_path, e.empId
